const leads = $input.all().map(item => item.json);

const opportunities = leads.filter(lead => lead.type === "opportunity");

const total = opportunities.length;
const withEmail = opportunities.filter(l => l.email_from || l.email_normalized).length;
const withPhone = opportunities.filter(l => l.phone).length;

const now = new Date();

const inactive = opportunities.filter(lead => {
  const lastUpdate = new Date(lead.write_date || lead.create_date);
  const diffDays = (now - lastUpdate) / (1000 * 60 * 60 * 24);
  return diffDays >= 7;
}).length;

const newThisWeek = opportunities.filter(lead => {
  const created = new Date(lead.create_date);
  const diffDays = (now - created) / (1000 * 60 * 60 * 24);
  return diffDays <= 7;
}).length;

return [
  {
    json: {
      total_opportunities: total,
      opportunities_with_email: withEmail,
      opportunities_with_phone: withPhone,
      inactive_opportunities: inactive,
      new_this_week: newThisWeek
    }
  }
];

const data = $json;

return [
  {
    json: {
      ...data,
      chatInput:
`Create a short CRM analytics summary for a sales manager.

CRM Data:
- Total opportunities: ${data.total_opportunities}
- Opportunities with email: ${data.opportunities_with_email}
- Opportunities with phone: ${data.opportunities_with_phone}
- Inactive opportunities: ${data.inactive_opportunities}
- New opportunities this week: ${data.new_this_week}

Return the result in this exact format:

CRM Daily Summary:
<2 short sentences>

Key Observations:
- <observation based exactly on the numbers>
- <observation based exactly on the numbers>

Recommended Action:
<one practical recommendation>

Strict rules:
- Do not invent numbers.
- Do not calculate new numbers unless explicitly obvious from the provided data.
- If email count equals total opportunities, say all opportunities have email.
- If phone count equals total opportunities, say all opportunities have phone.
- Mention that inactive opportunities need attention.
- Do not mention marketing effectiveness unless the data proves it.
- Use only the provided CRM data.`
    }
  }
];
